def build_cifar100_dataloaders(batch_size: int = 256, img_size: int = 224, dry_run: bool = False, n_train: int = 1024, n_test: int = 256) -> Tuple[DataLoader, DataLoader]:
    """If dry_run=True, uses FakeData to keep test quick and avoid downloads."""
    train_tf = RandAugLogger(img_size=img_size)
    test_tf = tv.transforms.Compose([
        tv.transforms.Resize(img_size),
        tv.transforms.ToTensor()
    ])
    if dry_run:
        train_set = tv.datasets.FakeData(size=n_train, image_size=(3, img_size, img_size), num_classes=100, transform=None)
        test_set = tv.datasets.FakeData(size=n_test, image_size=(3, img_size, img_size), num_classes=100, transform=test_tf)
    else:
        train_set = tv.datasets.CIFAR100(root='./data', train=True, download=True, transform=None)
        test_set = tv.datasets.CIFAR100(root='./data', train=False, download=True, transform=test_tf)

    def train_collate(batch):
        imgs, metas, labels = [], [], []
        for img, y in batch:
            img, meta = train_tf(img)
            imgs.append(img)
            metas.append(meta)
            labels.append(y)
        return torch.stack(imgs), torch.tensor(labels, dtype=torch.long), metas

    train_loader = DataLoader(train_set, batch_size=batch_size, shuffle=True, num_workers=2, collate_fn=train_collate)
    test_loader = DataLoader(test_set, batch_size=batch_size, shuffle=False, num_workers=2,
                             collate_fn=lambda batch: (
                                 torch.stack([x[0] if isinstance(x[0], torch.Tensor) else test_tf(x[0]) for x in batch]),
                                 torch.tensor([x[1] for x in batch], dtype=torch.long),
                                 [AugMeta(1.0, 1.0, 1.0, 1.0, 0.0, 0.0) for _ in batch]
                             ))
    return train_loader, test_loader


